import os
from pathlib import Path

async def execute(self, inputs):
    p = inputs.get('path') or self.get_parameter('path', '.')
    recursive = inputs.get('recursive') if inputs.get('recursive') is not None else self.get_parameter('recursive', False)
    try:
        path = Path(p)
        items = []
        if recursive:
            for root, dirs, files in os.walk(path):
                for d in dirs:
                    items.append(str(Path(root) / d))
                for f in files:
                    items.append(str(Path(root) / f))
        else:
            if path.exists():
                for entry in path.iterdir():
                    items.append(str(entry))
        res = items
    except Exception as e:
        try: self.log_info(f'List Directory error: {e}')
        except Exception: pass
        res = []

    await self.set_output('result', res)
    await self.set_output('exec_out', True)
    return {'result': res}
